public bool IsApplicableToLanguage(LanguageId? detectedLanguage)
    {
        if (ApplicableLanguages.Count == 0)
        {
            return true;
        }

        if (detectedLanguage is null)
        {
            return false;
        }

        return ApplicableLanguages.Any(l => string.Equals(l, detectedLanguage.Value.Value, StringComparison.OrdinalIgnoreCase));
    }

private JsonRpc EnsureConnected()
    {
        ObjectDisposedException.ThrowIf(_disposed, this);
        if (_rpc is null)
        {
            throw new InvalidOperationException("Not connected to auxiliary backchannel.");
        }
        return _rpc;
    }

public async Task<AppHostInformation?> GetAppHostInformationAsync(CancellationToken cancellationToken = default)
    {
        var rpc = EnsureConnected();

        _logger.LogDebug("Requesting AppHost information");

        var appHostInfo = await rpc.InvokeWithProfilingAsync<AppHostInformation?>(
            _profilingTelemetry,
            "auxiliary",
            "GetAppHostInformationAsync",
            [],
            cancellationToken).ConfigureAwait(false);

        return appHostInfo;
    }

public IAsyncEnumerable<ResourceLogLine> GetConsoleLogsAsync(
    GetConsoleLogsRequest request,
    CancellationToken cancellationToken = default)
{
    ArgumentNullException.ThrowIfNull(request);

    if (!SupportsV2)
    {
        // Fall back to v1
        return GetResourceLogsAsync(request.ResourceName, request.Follow, cancellationToken);
    }

    return GetConsoleLogsV2InternalAsync(request, cancellationToken);
}

public IAsyncEnumerable<BackchannelLogEntry> GetAppHostLogEntriesAsync(CancellationToken cancellationToken)
    {
        return InvokeStreamingRpcAsync<BackchannelLogEntry>(
            (rpc, ct) => rpc.InvokeStreamingWithProfilingAsync<BackchannelLogEntry>(
                profilingTelemetry, "apphost", "GetAppHostLogEntriesAsync", [], ct, ProfilingJsonRpcExtensions.StreamingSpanLifetime.FirstItem),
            "AppHost log entries",
            cancellationToken);
    }

public IAsyncEnumerable<RpcResourceState> GetResourceStatesAsync(CancellationToken cancellationToken)
    {
        return InvokeStreamingRpcAsync<RpcResourceState>(
            (rpc, ct) => rpc.InvokeStreamingWithProfilingAsync<RpcResourceState>(
                profilingTelemetry, "apphost", "GetResourceStatesAsync", [], ct),
            "resource states",
            cancellationToken);
    }

private void OnRpcDisconnected(object? sender, JsonRpcDisconnectedEventArgs args)
    {
        logger.LogDebug("Backchannel disconnected: {Reason}", args.Reason);
        lock (_lock)
        {
            _disconnectTaskCompletionSource.TrySetResult();
        }
    }
